ALTER TABLE public.banners ADD COLUMN IF NOT EXISTS expiry_days integer DEFAULT NULL, ADD COLUMN IF NOT EXISTS status text DEFAULT 'active'; UPDATE public.banners SET status = CASE WHEN is_active THEN 'active' ELSE 'inactive' END; CREATE OR REPLACE FUNCTION public.deactivate_expired_banners() RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN UPDATE public.banners SET is_active = false, status = 'expired' WHERE is_active = true AND expires_at IS NOT NULL AND expires_at < now(); END; $$;